13896   // truncated just before storing) without traversing the expression tree.
13897   // This is the common case.
13898   if (auto *Store = dyn_cast<StoreInst>(V))
13899     return DL->getTypeSizeInBits(Store->getValueOperand()->getType());
13900 
13901   if (auto *IEI = dyn_cast<InsertElementInst>(V))
13902     return getVectorElementSize(IEI->getOperand(1));
13903 
13904   auto E = InstrElementSize.find(V);
13905   if (E != InstrElementSize.end())
13906     return E->second;
13907 
13908   // If V is not a store, we can traverse the expression tree to find loads
13909   // that feed it. The type of the loaded value may indicate a more suitable
13910   // width than V's type. We want to base the vector element size on the width
13911   // of memory operations where possible.
13912   SmallVector<std::pair<Instruction *, BasicBlock *>, 16> Worklist;
13913   SmallPtrSet<Instruction *, 16> Visited;
13914   if (auto *I = dyn_cast<Instruction>(V)) {
13915     Worklist.emplace_back(I, I->getParent());
13916     Visited.insert(I);
13917   }
13918 
13919   // Traverse the expression tree in bottom-up order looking for loads. If we
13920   // encounter an instruction we don't yet handle, we give up.
13921   auto Width = 0u;
13922   while (!Worklist.empty()) {
13923     Instruction *I;
13924     BasicBlock *Parent;
13925     std::tie(I, Parent) = Worklist.pop_back_val();
13926 
