14043         !collectValuesToDemote(I->getOperand(0), IsProfitableToDemoteRoot,
14044                                BitWidth, ToDemote, DemotedConsts, Visited,
14045                                Level1, IsProfitableToDemote, IsTruncRoot) ||
14046         !collectValuesToDemote(I->getOperand(1), IsProfitableToDemoteRoot,
14047                                BitWidth, ToDemote, DemotedConsts, Visited,
14048                                Level2, IsProfitableToDemote, IsTruncRoot))
14049       return false;
14050     MaxDepthLevel = std::max(Level1, Level2);
14051     break;
14052   }
14053 
14054   // We can demote selects if we can demote their true and false values.
14055   case Instruction::Select: {
14056     Start = 1;
14057     unsigned Level1 = MaxDepthLevel, Level2 = MaxDepthLevel;
14058     SelectInst *SI = cast<SelectInst>(I);
14059     if ((ITE->UserTreeIndices.size() > 1 &&
14060          !IsPotentiallyTruncated(I, BitWidth)) ||
14061         !collectValuesToDemote(SI->getTrueValue(), IsProfitableToDemoteRoot,
14062                                BitWidth, ToDemote, DemotedConsts, Visited,
14063                                Level1, IsProfitableToDemote, IsTruncRoot) ||
14064         !collectValuesToDemote(SI->getFalseValue(), IsProfitableToDemoteRoot,
14065                                BitWidth, ToDemote, DemotedConsts, Visited,
14066                                Level2, IsProfitableToDemote, IsTruncRoot))
14067       return false;
14068     MaxDepthLevel = std::max(Level1, Level2);
14069     break;
14070   }
14071 
14072   // We can demote phis if we can demote all their incoming operands. Note that
14073   // we don't need to worry about cycles since we ensure single use above.
14074   case Instruction::PHI: {
14075     PHINode *PN = cast<PHINode>(I);
14076     if (ITE->UserTreeIndices.size() > 1 && !IsPotentiallyTruncated(I, BitWidth))
14077       return false;
14078     unsigned InitLevel = MaxDepthLevel;
14079     for (Value *IncValue : PN->incoming_values()) {
14080       unsigned Level = InitLevel;
14081       if (!collectValuesToDemote(IncValue, IsProfitableToDemoteRoot, BitWidth,
14082                                  ToDemote, DemotedConsts, Visited, Level,
14083                                  IsProfitableToDemote, IsTruncRoot))
14084         return false;
14085       MaxDepthLevel = std::max(MaxDepthLevel, Level);
14086     }
14087     break;
14088   }
14089 
14090   // Otherwise, conservatively give up.
14091   default:
14092     MaxDepthLevel = 1;
14093     return IsProfitableToDemote && IsPotentiallyTruncated(I, BitWidth);
14094   }
14095 
14096   ++MaxDepthLevel;
14097   // Gather demoted constant operands.
14098   for (unsigned Idx : seq<unsigned>(Start, End))
14099     if (isa<Constant>(I->getOperand(Idx)))
14100       DemotedConsts.try_emplace(I).first->getSecond().push_back(Idx);
14101   // Record the value that we can demote.
14102   ToDemote.push_back(V);
14103   return IsProfitableToDemote;
