14106 void BoUpSLP::computeMinimumValueSizes() {
14107   // We only attempt to truncate integer expressions.
14108   bool IsStoreOrInsertElt =
14109       VectorizableTree.front()->getOpcode() == Instruction::Store ||
14110       VectorizableTree.front()->getOpcode() == Instruction::InsertElement;
14111   if ((IsStoreOrInsertElt || UserIgnoreList) && TruncNodes.size() <= 1 &&
14112       (!CastMaxMinBWSizes || CastMaxMinBWSizes->second == 0 ||
14113        CastMaxMinBWSizes->first / CastMaxMinBWSizes->second <= 2))
14114     return;
14115 
14116   unsigned NodeIdx = 0;
14117   if (IsStoreOrInsertElt &&
14118       VectorizableTree.front()->State != TreeEntry::NeedToGather)
14119     NodeIdx = 1;
14120 
14121   // Ensure the roots of the vectorizable tree don't form a cycle.
14122   if (VectorizableTree[NodeIdx]->State == TreeEntry::NeedToGather ||
14123       (NodeIdx == 0 && !VectorizableTree[NodeIdx]->UserTreeIndices.empty()) ||
14124       (NodeIdx != 0 && any_of(VectorizableTree[NodeIdx]->UserTreeIndices,
14125                               [NodeIdx](const EdgeInfo &EI) {
14126                                 return EI.UserTE->Idx >
14127                                        static_cast<int>(NodeIdx);
14128                               })))
14129     return;
14130 
14131   // The first value node for store/insertelement is sext/zext/trunc? Skip it,
14132   // resize to the final type.
14133   bool IsProfitableToDemoteRoot = !IsStoreOrInsertElt;
14134   if (NodeIdx != 0 &&
14135       VectorizableTree[NodeIdx]->State == TreeEntry::Vectorize &&
14136       (VectorizableTree[NodeIdx]->getOpcode() == Instruction::ZExt ||
14137        VectorizableTree[NodeIdx]->getOpcode() == Instruction::SExt ||
14138        VectorizableTree[NodeIdx]->getOpcode() == Instruction::Trunc)) {
14139     assert(IsStoreOrInsertElt && "Expected store/insertelement seeded graph.");
14140     ++NodeIdx;
14141     IsProfitableToDemoteRoot = true;
14142   }
14143 
14144   // Analyzed in reduction already and not profitable - exit.
14145   if (AnalyzedMinBWVals.contains(VectorizableTree[NodeIdx]->Scalars.front()))
14146     return;
14147 
14148   SmallVector<Value *> ToDemote;
14149   DenseMap<Instruction *, SmallVector<unsigned>> DemotedConsts;
14150   auto ComputeMaxBitWidth = [&](ArrayRef<Value *> TreeRoot, unsigned VF,
14151                                 bool IsTopRoot, bool IsProfitableToDemoteRoot,
14152                                 unsigned Opcode, unsigned Limit, bool IsTruncRoot) {
14153     ToDemote.clear();
14154     auto *TreeRootIT = dyn_cast<IntegerType>(TreeRoot[0]->getType());
14155     if (!TreeRootIT || !Opcode)
14156       return 0u;
14157 
14158     if (AnalyzedMinBWVals.contains(TreeRoot.front()))
14159       return 0u;
14160 
14161     unsigned NumParts = TTI->getNumberOfParts(
14162         FixedVectorType::get(TreeRoot.front()->getType(), VF));
14163 
14164     // The maximum bit width required to represent all the values that can be
14165     // demoted without loss of precision. It would be safe to truncate the roots
14166     // of the expression to this width.
14167     unsigned MaxBitWidth = 1u;
14168 
14169     // True if the roots can be zero-extended back to their original type,
14170     // rather than sign-extended. We know that if the leading bits are not
14171     // demanded, we can safely zero-extend. So we initialize IsKnownPositive to
14172     // True.
14173     // Determine if the sign bit of all the roots is known to be zero. If not,
14174     // IsKnownPositive is set to False.
14175     bool IsKnownPositive = all_of(TreeRoot, [&](Value *R) {
14176       KnownBits Known = computeKnownBits(R, *DL);
14177       return Known.isNonNegative();
14178     });
14179 
14180     // We first check if all the bits of the roots are demanded. If they're not,
14181     // we can truncate the roots to this narrower type.
14182     for (auto *Root : TreeRoot) {
14183       unsigned NumSignBits = ComputeNumSignBits(Root, *DL, 0, AC, nullptr, DT);
14184       TypeSize NumTypeBits = DL->getTypeSizeInBits(Root->getType());
14185       unsigned BitWidth1 = NumTypeBits - NumSignBits;
14186       // If we can't prove that the sign bit is zero, we must add one to the
14187       // maximum bit width to account for the unknown sign bit. This preserves
14188       // the existing sign bit so we can safely sign-extend the root back to the
14189       // original type. Otherwise, if we know the sign bit is zero, we will
14190       // zero-extend the root instead.
14191       //
14192       // FIXME: This is somewhat suboptimal, as there will be cases where adding
14193       //        one to the maximum bit width will yield a larger-than-necessary
14194       //        type. In general, we need to add an extra bit only if we can't
14195       //        prove that the upper bit of the original type is equal to the
14196       //        upper bit of the proposed smaller type. If these two bits are
14197       //        the same (either zero or one) we know that sign-extending from
14198       //        the smaller type will result in the same value. Here, since we
14199       //        can't yet prove this, we are just making the proposed smaller
14200       //        type larger to ensure correctness.
14201       if (!IsKnownPositive)
14202         ++BitWidth1;
14203 
14204       APInt Mask = DB->getDemandedBits(cast<Instruction>(Root));
14205       unsigned BitWidth2 = Mask.getBitWidth() - Mask.countl_zero();
14206       MaxBitWidth =
14207           std::max<unsigned>(std::min(BitWidth1, BitWidth2), MaxBitWidth);
14208     }
14209 
14210     if (MaxBitWidth < 8 && MaxBitWidth > 1)
14211       MaxBitWidth = 8;
14212 
14213     // If the original type is large, but reduced type does not improve the reg
14214     // use - ignore it.
14215     if (NumParts > 1 &&
14216         NumParts ==
14217             TTI->getNumberOfParts(FixedVectorType::get(
14218                 IntegerType::get(F->getContext(), bit_ceil(MaxBitWidth)), VF)))
14219       return 0u;
14220 
14221     bool IsProfitableToDemote = Opcode == Instruction::Trunc ||
14222                                 Opcode == Instruction::SExt ||
14223                                 Opcode == Instruction::ZExt || NumParts > 1;
14224     // Conservatively determine if we can actually truncate the roots of the
14225     // expression. Collect the values that can be demoted in ToDemote and
14226     // additional roots that require investigating in Roots.
14227     for (auto *Root : TreeRoot) {
14228       DenseSet<Value *> Visited;
14229       unsigned MaxDepthLevel = IsTruncRoot ? Limit : 1;
14230       bool NeedToDemote = IsProfitableToDemote;
14231 
14232       if (!collectValuesToDemote(Root, IsProfitableToDemoteRoot, MaxBitWidth,
14233                                  ToDemote, DemotedConsts, Visited,
14234                                  MaxDepthLevel, NeedToDemote, IsTruncRoot) ||
14235           (MaxDepthLevel <= Limit &&
14236            !(((Opcode == Instruction::SExt || Opcode == Instruction::ZExt) &&
14237               (!IsTopRoot || !(IsStoreOrInsertElt || UserIgnoreList) ||
14238                DL->getTypeSizeInBits(Root->getType()) /
14239                        DL->getTypeSizeInBits(
14240                            cast<Instruction>(Root)->getOperand(0)->getType()) >
14241                    2)))))
14242         return 0u;
14243     }
14244     // Round MaxBitWidth up to the next power-of-two.
14245     MaxBitWidth = bit_ceil(MaxBitWidth);
14246 
14247     return MaxBitWidth;
14248   };
