15126   static RecurKind getRdxKind(Value *V) {
15127     auto *I = dyn_cast<Instruction>(V);
15128     if (!I)
15129       return RecurKind::None;
15130     if (match(I, m_Add(m_Value(), m_Value())))
15131       return RecurKind::Add;
15132     if (match(I, m_Mul(m_Value(), m_Value())))
15133       return RecurKind::Mul;
15134     if (match(I, m_And(m_Value(), m_Value())) ||
15135         match(I, m_LogicalAnd(m_Value(), m_Value())))
15136       return RecurKind::And;
15137     if (match(I, m_Or(m_Value(), m_Value())) ||
15138         match(I, m_LogicalOr(m_Value(), m_Value())))
15139       return RecurKind::Or;
15140     if (match(I, m_Xor(m_Value(), m_Value())))
15141       return RecurKind::Xor;
15142     if (match(I, m_FAdd(m_Value(), m_Value())))
15143       return RecurKind::FAdd;
15144     if (match(I, m_FMul(m_Value(), m_Value())))
15145       return RecurKind::FMul;
15146 
15147     if (match(I, m_Intrinsic<Intrinsic::maxnum>(m_Value(), m_Value())))
15148       return RecurKind::FMax;
15149     if (match(I, m_Intrinsic<Intrinsic::minnum>(m_Value(), m_Value())))
15150       return RecurKind::FMin;
15151 
15152     if (match(I, m_Intrinsic<Intrinsic::maximum>(m_Value(), m_Value())))
15153       return RecurKind::FMaximum;
15154     if (match(I, m_Intrinsic<Intrinsic::minimum>(m_Value(), m_Value())))
15155       return RecurKind::FMinimum;
15156     // This matches either cmp+select or intrinsics. SLP is expected to handle
15157     // either form.
15158     // TODO: If we are canonicalizing to intrinsics, we can remove several
15159     //       special-case paths that deal with selects.
15160     if (match(I, m_SMax(m_Value(), m_Value())))
15161       return RecurKind::SMax;
15162     if (match(I, m_SMin(m_Value(), m_Value())))
15163       return RecurKind::SMin;
15164     if (match(I, m_UMax(m_Value(), m_Value())))
15165       return RecurKind::UMax;
15166     if (match(I, m_UMin(m_Value(), m_Value())))
15167       return RecurKind::UMin;
15168 
15169     if (auto *Select = dyn_cast<SelectInst>(I)) {
15170       // Try harder: look for min/max pattern based on instructions producing
15171       // same values such as: select ((cmp Inst1, Inst2), Inst1, Inst2).
15172       // During the intermediate stages of SLP, it's very common to have
15173       // pattern like this (since optimizeGatherSequence is run only once
15174       // at the end):
15175       // %1 = extractelement <2 x i32> %a, i32 0
15176       // %2 = extractelement <2 x i32> %a, i32 1
15177       // %cond = icmp sgt i32 %1, %2
15178       // %3 = extractelement <2 x i32> %a, i32 0
15179       // %4 = extractelement <2 x i32> %a, i32 1
15180       // %select = select i1 %cond, i32 %3, i32 %4
15181       CmpInst::Predicate Pred;
15182       Instruction *L1;
15183       Instruction *L2;
15184 
15185       Value *LHS = Select->getTrueValue();
15186       Value *RHS = Select->getFalseValue();
15187       Value *Cond = Select->getCondition();
15188 
15189       // TODO: Support inverse predicates.
15190       if (match(Cond, m_Cmp(Pred, m_Specific(LHS), m_Instruction(L2)))) {
15191         if (!isa<ExtractElementInst>(RHS) ||
15192             !L2->isIdenticalTo(cast<Instruction>(RHS)))
15193           return RecurKind::None;
15194       } else if (match(Cond, m_Cmp(Pred, m_Instruction(L1), m_Specific(RHS)))) {
15195         if (!isa<ExtractElementInst>(LHS) ||
15196             !L1->isIdenticalTo(cast<Instruction>(LHS)))
15197           return RecurKind::None;
15198       } else {
15199         if (!isa<ExtractElementInst>(LHS) || !isa<ExtractElementInst>(RHS))
15200           return RecurKind::None;
15201         if (!match(Cond, m_Cmp(Pred, m_Instruction(L1), m_Instruction(L2))) ||
15202             !L1->isIdenticalTo(cast<Instruction>(LHS)) ||
15203             !L2->isIdenticalTo(cast<Instruction>(RHS)))
15204           return RecurKind::None;
15205       }
15206 
15207       switch (Pred) {
15208       default:
15209         return RecurKind::None;
15210       case CmpInst::ICMP_SGT:
15211       case CmpInst::ICMP_SGE:
15212         return RecurKind::SMax;
15213       case CmpInst::ICMP_SLT:
15214       case CmpInst::ICMP_SLE:
15215         return RecurKind::SMin;
15216       case CmpInst::ICMP_UGT:
15217       case CmpInst::ICMP_UGE:
15218         return RecurKind::UMax;
15219       case CmpInst::ICMP_ULT:
15220       case CmpInst::ICMP_ULE:
15221         return RecurKind::UMin;
15222       }
15223     }
15224     return RecurKind::None;
15225   }
